// primary queue drain surface without switching commands.
func TestWorkCommandHasAllExecuteLoopFlags(t *testing.T) {
	dir := t.TempDir()
	root := NewCommandFactory(dir).NewRootCommand()

	workCmd, _, err := root.Find([]string{"work"})
